if (! function_exists('delete_file')) {
    function delete_file($path)
    {
        $baseDir = str_replace('\\', '/', realpath(__DIR__ . '/../../..'));
        if ($baseDir === false || empty($baseDir)) {
            return 'Error: Could not resolve project directory.';
        }

        $requested = $path;
        if (!is_string($requested) || trim($requested) === '') {
            return 'Error: Path must be a non-empty string.';
        }

        $requested = str_replace('\\', '/', trim($requested));
        $requested = ltrim($requested, '/');

        if (str_contains($requested, "\0")) {
            return 'Error: Path contains an invalid null byte.';
        }

        $full = realpath($baseDir . '/' . $requested);
        if ($full === false) {
            return 'Error: Path does not exist or is invalid: ' . $path;
        }

        $full = str_replace('\\', '/', $full);

        // Must be within project
        if ($full !== $baseDir && strpos($full, $baseDir . '/') !== 0) {
            return 'Error: Path is outside the project directory.';
        }

        // Block dangerous paths
        $relative = ltrim(substr($full, strlen($baseDir)), '/');
        $parts = explode('/', $relative);
        foreach ($parts as $part) {
            if ($part === '.env' || $part === 'vendor' || $part === '.git' || $part === 'node_modules') {
                return 'Error: Cannot delete files in restricted paths (.env, vendor, .git, node_modules).';
            }
        }

        // Don't delete files from project root
        if (!str_contains($relative, '/')) {
            return 'Error: Cannot delete files from project root for safety.';
        }

        if (!is_file($full)) {
            return 'Error: Not a file or does not exist: ' . $path;
        }

        if (unlink($full)) {
            return 'Success: Deleted ' . $path . ' (' . $relative . ')';
        }

        return 'Error: Failed to delete ' . $path;
    }
